const EXTENSIONES_VALIDAS = [
  '.py', '.js', '.ts', '.jsx', '.tsx',
  '.java', '.go', '.rb', '.php', '.cs',
  '.cpp', '.c', '.rs', '.swift', '.kt',
  '.md'
];

const ARCHIVOS_EXCLUIDOS = [
  'package-lock.json', 'yarn.lock', 'pnpm-lock.yaml',
  'poetry.lock', 'Gemfile.lock', '.env.example'
];

const archivos = $input.all();

const filtrados = archivos.filter(item => {
  const filename = item.json.filename;
  const ext = '.' + filename.split('.').pop();

  // Excluir archivos no relevantes
  if (ARCHIVOS_EXCLUIDOS.some(e => filename.endsWith(e))) return false;

  // Solo extensiones de código
  if (!EXTENSIONES_VALIDAS.includes(ext)) return false;

  // Excluir archivos eliminados (no hay nada que revisar)
  if (item.json.status === 'removed') return false;

  // Excluir patches muy grandes (>300 líneas cambiadas)
  if ((item.json.additions + item.json.deletions) > 300) return false;

  return true;
});

return filtrados;

// Necesitas cruzar el patch del paso anterior con el archivo actual
const archivosConPatch = $('filter_files').all(); // ajusta el nombre al de tu nodo

return $input.all().map(item => {
  const contenido = Buffer.from(item.json.content, 'base64').toString('utf-8');

  // Buscar el patch correspondiente por path
  const archivoOriginal = archivosConPatch.find(
    a => a.json.filename === item.json.path
  );

  return {
    json: {
      filename: item.json.name,
      path: item.json.path,
      contenido: contenido,
      patch: archivoOriginal?.json.patch ?? 'No disponible'
    }
  };
});

const SD = $getWorkflowStaticData('node');
const API_KEY = "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";

if (!API_KEY) throw new Error('OPENAI_API_KEY no definida');

if (!SD.weights) {
  SD.weights = {
    seguridad:      { w: [0,0,0,0,0,0,0,0,0], alpha: 0.2, beta: 0.1 },
    estructuras:    { w: [0,0,0,0,0,0,0,0,0], alpha: 0.2, beta: 0.1 },
    calidad:        { w: [0,0,0,0,0,0,0,0,0], alpha: 0.2, beta: 0.1 },
    performance:    { w: [0,0,0,0,0,0,0,0,0], alpha: 0.2, beta: 0.1 },
    documentacion:  { w: [0,0,0,0,0,0,0,0,0], alpha: 0.2, beta: 0.1 },
  };
  SD.epsilon = 0.3;
  SD.count = 0;
  SD.history = [];
}

const SYS_PROMPTS = {
  seguridad: `Eres un experto en ciberseguridad especializado en revisión de código seguro. Tu única tarea es analizar el código que te proporcionen e identificar problemas de seguridad.

Busca específicamente:
- Vulnerabilidades OWASP Top 10 (inyección SQL, XSS, CSRF, etc.)
- Credenciales, tokens o secretos hardcodeados
- Autenticación o autorización débil o ausente
- Manejo inseguro de datos sensibles o contraseñas
- Exposición innecesaria de información en errores o logs
- Dependencias con vulnerabilidades conocidas

Reglas:
- Solo reporta problemas reales, no hipotéticos
- Si no hay problemas, di que el archivo es seguro
- Sé específico con el número de línea cuando puedas
- No comentes sobre estilo ni calidad de código, solo seguridad

Responde SIEMPRE en este formato JSON exacto, sin texto adicional antes ni después:
{"path": "path_archivo", "issues":[{"severidad":"crítica|alta|media|baja","linea":"número o rango","descripcion":"descripción del problema","sugerencia":"cómo arreglarlo"}],"resumen":"una línea con el veredicto general"}`,
  estructuras: `Eres un experto en algoritmos y estructuras de datos. Tu única tarea es analizar el código que te proporcionen e identificar uso ineficiente de estructuras de datos y algoritmos.

Busca específicamente:
- Complejidad algorítmica innecesariamente alta (O(n²) evitable, búsquedas lineales donde se puede usar un set/dict, etc.)
- Estructura de datos incorrecta para el caso de uso (lista donde debería ser set, dict donde debería ser lista, etc.)
- Loops anidados que podrían simplificarse
- Recursión sin memoización donde el rendimiento importa
- Ordenamientos o búsquedas redundantes

Reglas:
- Solo reporta problemas con impacto real en rendimiento
- Explica la complejidad actual vs la esperada cuando aplique
- Si el código es eficiente, dilo explícitamente
- No comentes sobre seguridad ni estilo, solo estructuras y algoritmos

Responde SIEMPRE en este formato JSON exacto, sin texto adicional antes ni después:
{"path": "path_archivo", "issues":[{"severidad":"alta|media|baja","linea":"número o rango","descripcion":"descripción del problema","sugerencia":"cómo arreglarlo"}],"resumen":"una línea con el veredicto general"}`,
  calidad: `Eres un experto en calidad y arquitectura de software. Tu única tarea es analizar el código que te proporcionen e identificar problemas de calidad, mantenibilidad y buenas prácticas.

Busca específicamente:
- Violaciones de principios SOLID
- Funciones o clases con múltiples responsabilidades
- Código duplicado o lógica copy-paste
- Nombres de variables, funciones o clases poco descriptivos o confusos
- Funciones demasiado largas (más de 30-40 líneas)
- Código muerto, comentado o inalcanzable
- Magic numbers o strings sin constante nombrada
- Manejo de errores ausente o genérico

Reglas:
- Prioriza problemas que afecten mantenibilidad real
- Si el código es limpio, dilo explícitamente
- No comentes sobre seguridad ni performance, solo calidad
- Sé constructivo y específico en las sugerencias

Responde SIEMPRE en este formato JSON exacto, sin texto adicional antes ni después:
{"path": "path_archivo", "issues":[{"severidad":"alta|media|baja","linea":"número o rango","descripcion":"descripción del problema","sugerencia":"cómo arreglarlo"}],"resumen":"una línea con el veredicto general"}`,
  performance: `Eres un experto en optimización y performance de aplicaciones. Tu única tarea es analizar el código que te proporcionen e identificar cuellos de botella y problemas de rendimiento.

Busca específicamente:
- Queries N+1 o llamadas a base de datos dentro de loops
- Operaciones síncronas bloqueantes que deberían ser asíncronas
- Falta de paginación en consultas que pueden devolver muchos registros
- Ausencia de caché donde claramente sería beneficioso
- Carga innecesaria de datos completos cuando solo se necesitan campos específicos
- Memory leaks potenciales o acumulación innecesaria de objetos en memoria
- Operaciones costosas ejecutadas repetidamente sin necesidad

Reglas:
- Solo reporta problemas con impacto medible en rendimiento
- Estima el impacto cuando sea posible (ej: "esto genera N queries por cada item")
- Si el código es eficiente, dilo explícitamente
- No comentes sobre seguridad ni calidad de código, solo performance

Responde SIEMPRE en este formato JSON exacto, sin texto adicional antes ni después:
{"path": "path_archivo", "issues":[{"severidad":"alta|media|baja","linea":"número o rango","descripcion":"descripción del problema","sugerencia":"cómo arreglarlo"}],"resumen":"una línea con el veredicto general"}`,
  documentacion: `Eres un experto en documentación y comunicación técnica. Tu única tarea es analizar el código que te proporcionen e identificar problemas de documentación y claridad.

Busca específicamente:
- Funciones o métodos públicos sin docstring o JSDoc
- Clases sin descripción de su responsabilidad
- Lógica compleja o no obvia sin comentarios explicativos
- Parámetros y valores de retorno sin tipar ni documentar
- TODOs o FIXMEs sin ticket o contexto asociado
- Ausencia de ejemplos de uso en funciones críticas o públicas
- Comentarios obsoletos que ya no corresponden al código

Reglas:
- Enfócate en documentación que realmente ayude a otros desarrolladores
- No pidas documentar código obvio o autoexplicativo
- Si la documentación es adecuada, dilo explícitamente
- No comentes sobre seguridad, performance ni calidad, solo documentación

Responde SIEMPRE en este formato JSON exacto, sin texto adicional antes ni después:
{"path": "path_archivo", "issues":[{"severidad":"media|baja","linea":"número o rango","descripcion":"descripción del problema","sugerencia":"cómo arreglarlo"}],"resumen":"una línea con el veredicto general"}`
};

const agents = ['seguridad', 'estructuras', 'calidad', 'performance', 'documentacion'];
const allResults = [];
const items = $input.all();

for (const item of items) {
  const data = item.json;
  SD.count++;

  const path = data.path || '';
  const patch = data.patch || '';
  const linesChanged = (patch.match(/^[+-]/gm) || []).length;
  const ext = path.split('.').pop().toLowerCase();
  const exts = { py:0, js:0, ts:0, java:0, go:0, rb:0, php:0, cs:0 };
  if (ext in exts) exts[ext] = 1;
  const features = [exts.py, exts.js, exts.ts, exts.java, exts.go, exts.rb, exts.php, exts.cs, Math.min(linesChanged/300, 1)];

  const analisis = {};
  const decisions = {};

  for (const agent of agents) {
    const { w, alpha, beta } = SD.weights[agent];
    const score = w.reduce((s, wi, i) => s + wi * features[i], 0);
    const explore = Math.random() < SD.epsilon;
    const run = explore ? Math.random() < 0.5 : score > 0;

    decisions[agent] = { ran: run, score, features: features.slice(), explore };

    if (run) {
      try {
        const response = await this.helpers.httpRequest({
          method: 'POST',
          url: 'https://api.openai.com/v1/chat/completions',
          headers: { 'Content-Type': 'application/json', 'Authorization': `Bearer ${API_KEY}` },
          body: {
            model: 'gpt-4o-mini',
            messages: [
              { role: 'system', content: SYS_PROMPTS[agent] },
              { role: 'user', content: `Archivo:\n${path}\n\nContenido\n${data.contenido || ''}\n\nDiff del PR:\n${patch}` }
            ],
            temperature: 0
          },
          json: true
        });
        const output = response.choices?.[0]?.message?.content || '{}';
        const clean = output.replace(/```json|```/g, '').trim();
        const result = JSON.parse(clean);
        analisis[agent] = result;

        const found = (result.issues || []).length > 0;
        const reward = found ? 1.0 : -0.5;
        const lr = found ? alpha : beta;
        features.forEach((f, i) => { w[i] += lr * (reward - score) * f; });
      } catch (e) {
        analisis[agent] = { path, issues: [], resumen: `Error: ${e.message}` };
      }
    } else {
      analisis[agent] = { path, issues: [], resumen: `__SKIPPED__ (score: ${score.toFixed(2)}, explore: ${explore})` };
    }
  }

  if (SD.count % 10 === 0 && SD.epsilon > 0.05) {
    SD.epsilon = Math.max(0.05, SD.epsilon * 0.95);
  }

  SD.history.push(decisions);
  SD.resultados = SD.resultados || [];
  SD.resultados.push({ path, analisis });
  allResults.push({ path, analisis });
}

return [{ json: { resultados: allResults } }];
